    mitreTechniques: ['T1087.002', 'T1135', 'T1069.002', 'T1558.003'],
    nistControls: ['AC-6', 'CM-7', 'SC-28', 'AU-12'],
    quiz: [
      { id: 'M11-Q01', question: 'Running `GetUserSPNs.py GFS.LOCAL/a.mercer -dc-ip 10.10.20.50 -request` returns Kerberos service tickets for svc-oracle and svc-backup. What attack does this enable and what defensive control prevents it?', options: ['Pass-the-Hash — prevented by disabling NTLM', 'Kerberoasting (T1558.003) — service tickets encrypted with account password are cracked offline. Prevented by: 25+ char random service account passwords, managed service accounts (gMSA), AES-256 only encryption', 'Golden Ticket — prevented by protecting KRBTGT account', 'AS-REP Roasting — prevented by enabling pre-authentication'], correctIndex: 1, explanation: 'GetUserSPNs.py (from Impacket) requests Kerberos service tickets for SPN-registered accounts. The tickets are encrypted with the service account\'s NTLM hash — crackable offline with Hashcat. Defenses: (1) Group Managed Service Accounts (gMSA) with auto-rotating 240-character passwords — computationally impossible to crack, (2) Remove RC4 support for service accounts (require AES-256), (3) Audit SPN registrations quarterly — remove unnecessary SPNs.', difficulty: 'Expert' },
      { id: 'M11-Q02', question: 'An enum4linux scan returns: `Share [SYSVOL] Access: READ | Share [NETLOGON] Access: READ | Share [gfs-scripts] Access: READ WRITE`. What is the critical finding?', options: ['SYSVOL access is expected for domain members', 'READ WRITE access to gfs-scripts share allows any domain user to place malicious scripts that may be executed by other users or automated processes — lateral movement risk', 'NETLOGON is only readable so it presents no risk', 'These are default Windows shares with no security implications'], correctIndex: 1, explanation: 'SYSVOL and NETLOGON read access is normal for domain members. However, READ WRITE access to gfs-scripts (a non-default share) allows any authenticated domain user to plant malicious scripts. If these scripts are executed by privileged accounts (service accounts, admins), this enables privilege escalation. GFS should implement: quarterly share permission audits, monitoring for file writes to admin shares, and least-privilege share ACLs.', difficulty: 'Applied' },
      { id: 'M11-Q03', question: 'SNMP v1 enumeration with community string "public" against GFS-NET-0002 (Palo Alto firewall) returns full interface configurations, routing tables, and VLAN assignments. What is the severity of this finding?', options: ['Low — SNMP read-only access is standard network management', 'Critical — SNMP v1 with default "public" community string exposes complete network topology to any unauthenticated attacker, enabling precise network mapping for targeted attacks', 'Medium — Routing tables are not sensitive information', 'Informational — Only network administrators can access SNMP'], correctIndex: 1, explanation: 'SNMP v1 with "public" community string is: (1) unauthenticated — any host can query it, (2) unencrypted — queries and responses visible in plaintext, (3) using the default community string known to every attacker. The returned data (interface IPs, routing tables, VLAN assignments, ARP caches) provides complete internal network topology. Remediation: upgrade to SNMPv3 with authentication (SHA-256) and encryption (AES-256), change community strings, implement ACLs restricting SNMP to NOC management hosts only (VLAN 999).', difficulty: 'Expert' },
      { id: 'M11-Q04', question: 'DNS zone transfer command: `dig axfr globalfinancial.com @ns1.globalfinancial.com`. What does a successful zone transfer reveal and how should GFS prevent it?', options: ['Only the public A records — no security impact', 'Complete internal DNS zone including all hostnames, IPs, MX records, internal service names — exposing the entire infrastructure map. Prevented by ACL restricting AXFR to authorized secondary DNS servers only', 'Encrypted zone data that cannot be read without a key', 'Only records that have public-facing services'], correctIndex: 1, explanation: 'A successful AXFR (zone transfer) returns every DNS record in the zone: A records (hostnames to IPs), CNAME records (aliases revealing service relationships), MX records (mail infrastructure), SRV records (service discovery), TXT records (SPF/DKIM/internal metadata). For GFS, this would expose: internal server names matching CMDB, service topology, and infrastructure that should be internal-only. Prevention: configure BIND/Windows DNS to allow AXFR only from authorized secondary NS server IPs using `allow-transfer { secondary-ip; };`.', difficulty: 'Expert' },
      { id: 'M11-Q05', question: 'BloodHound analysis of the GFS Active Directory shows: a.mercer (SOC Analyst) → MemberOf → IT-Support-Tier1 → WriteDACL → Domain Admins. What attack path does this create?', options: ['This is a normal permission structure for IT support roles', 'A.mercer can exploit WriteDACL on Domain Admins to grant themselves membership, achieving full domain compromise — this is a critical BloodHound attack path (ACL abuse)', 'WriteDACL only allows reading access control lists, not modifying them', 'The path requires physical access to a domain controller'], correctIndex: 1, explanation: 'WriteDACL (Write Discretionary Access Control List) permission on the Domain Admins group means the IT-Support-Tier1 group can modify the group\'s access control list — including adding themselves as members. Attack: a.mercer uses PowerView AddDomainObjectAcl to grant their account GenericAll on Domain Admins, then adds themselves. This achieves full domain compromise through ACL abuse (T1484.001). BloodHound path analysis is essential for detecting these non-obvious privilege escalation routes in complex AD environments.', difficulty: 'Expert' },
    ],
    labSteps: [
      { stepNumber: 1, title: 'LDAP Enumeration', instruction: 'Query the GFS Active Directory LDAP to enumerate all user accounts in the "GFS-SOC-LEVEL3" security group.', command: 'ldapsearch -x -H ldap://10.10.20.50 -b "DC=GFS,DC=LOCAL" -D "a.mercer@gfs.local" -W "(memberOf=CN=GFS-SOC-LEVEL3,CN=Users,DC=GFS,DC=LOCAL)" sAMAccountName', expectedOutput: 'sAMAccountName: a.jenkins\nsAMAccountName: c.brody\nsAMAccountName: a.mercer', hint: 'LDAP filter (memberOf=CN=groupname,...) returns all members. Use -x for simple authentication, -b for base DN, -D for bind DN.' },
      { stepNumber: 2, title: 'Kerberoast SPNs', instruction: 'Enumerate all SPN-registered service accounts vulnerable to Kerberoasting. Identify accounts using RC4 encryption.', command: 'GetUserSPNs.py GFS.LOCAL/a.mercer -dc-ip 10.10.20.50 -request -outputfile spn-hashes.txt', expectedOutput: '$krb5tgs$23$*svc-oracle$GFS.LOCAL$oracle/ny-dc01-corebank-db01.gfs.local*$...\n$krb5tgs$23$*svc-backup$GFS.LOCAL$backup/ny-dc01-backup01.gfs.local*$...', hint: 'etype 23 ($krb5tgs$23$) = RC4 encryption = crackable. etype 18 = AES-256 = much harder to crack.' },
      { stepNumber: 3, title: 'Submit Flag', instruction: 'What Impacket tool is used to enumerate Kerberoastable service accounts?', command: '', expectedOutput: 'GetUserSPNs.py', hint: 'This Impacket script specifically targets Service Principal Name enumeration and ticket extraction.' },
    ],
